// ── Анимированная звёздочка ────────────────────────────────────────────────────
function AnimStar({ delay, isGain, color }: { delay: number; isGain: boolean; color: string }) {
  const scale = useRef(new Animated.Value(0)).current;
  const translateY = useRef(new Animated.Value(isGain ? 20 : -20)).current;
  const opacity = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    const anim = Animated.sequence([
      Animated.delay(delay),
      Animated.parallel([
        Animated.spring(scale, { toValue: 1, useNativeDriver: true, friction: 4, tension: 120 }),
        Animated.timing(translateY, { toValue: 0, duration: 400, useNativeDriver: true, easing: Easing.out(Easing.back(2)) }),
        Animated.timing(opacity, { toValue: 1, duration: 200, useNativeDriver: true }),
      ]),
    ]);
    anim.start();
  }, []);

  return (
    <Animated.Text style={{
      fontSize: 28,
      transform: [{ scale }, { translateY }],
      opacity,
      color,
    }}>
      {isGain ? '⭐' : '💔'}
    </Animated.Text>
  );
}

// ── Блок звёздочек (+1/-1 из текущих звёзд) ─────────────────────────────────
function StarReward({ gained, lost, accentColor, wrongColor }: {
  gained: number; lost: number; accentColor: string; wrongColor: string;
}) {
  if (gained === 0 && lost === 0) return null;
  return (
    <View style={{ flexDirection: 'row', alignItems: 'center', gap: 6 }}>
      {Array.from({ length: gained }).map((_, i) => (
        <AnimStar key={`g${i}`} delay={i * 150} isGain color={accentColor} />
      ))}
      {Array.from({ length: lost }).map((_, i) => (
        <AnimStar key={`l${i}`} delay={i * 150} isGain={false} color={wrongColor} />
      ))}
    </View>
  );
}

